1	#!/usr/bin/env node
2	import { Buffer } from "node:buffer";
3	import { existsSync } from "node:fs";
4	import { mkdir, readFile, writeFile } from "node:fs/promises";
5	import { createServer } from "node:http";
6	import path from "node:path";
7	import { fileURLToPath } from "node:url";
8	import { chromium } from "@playwright/test";
9	import { browserLaunchOptions, sha256File } from "./render-shared.mjs";
10	
11	const __dirname = path.dirname(fileURLToPath(import.meta.url));
12	const repoRoot = path.resolve(__dirname, "..", "..");
13	const manifestPath = path.join(__dirname, "real-models.manifest.json");
14	const visualRoot = path.join(repoRoot, "test-results", "visual", "real-models");
15	const supportedModes = new Set(["current", "baseline"]);
16	const dataRootEnvName = "MMD_DATA_ROOT";
17	
18	const mimeTypes = new Map([
19	  [".js", "text/javascript; charset=utf-8"],
20	  [".mjs", "text/javascript; charset=utf-8"],
21	  [".json", "application/json; charset=utf-8"],
22	  [".wasm", "application/wasm"],
23	  [".html", "text/html; charset=utf-8"],
24	  [".pmx", "application/octet-stream"],
25	  [".pmd", "application/octet-stream"],
26	  [".vmd", "application/octet-stream"],
27	  [".vpd", "text/plain; charset=utf-8"],
28	  [".bmp", "image/bmp"],
29	  [".png", "image/png"],
30	  [".jpg", "image/jpeg"],
31	  [".jpeg", "image/jpeg"],
32	  [".tga", "application/octet-stream"],
33	  [".sph", "image/bmp"],
34	  [".spa", "image/bmp"]
35	]);
36	
37	async function main() {
38	  const options = parseArgs(process.argv.slice(2));
39	  const dataRoot = options.dataRoot ?? process.env[dataRootEnvName];
40	  if (!dataRoot) {
41	    console.log(`Local real-model profile skipped: ${dataRootEnvName} is not set and --data-root was not provided.`);
42	    return;
43	  }
44	
45	  const resolvedDataRoot = path.resolve(dataRoot);
46	  if (!existsSync(resolvedDataRoot)) {
47	    console.log(`Local real-model profile skipped: ${dataRootEnvName} does not exist: ${resolvedDataRoot}`);
48	    return;
49	  }
50	
51	  if (!existsSync(path.join(repoRoot, "dist", "three", "index.js"))) {
52	    throw new Error("dist/three/index.js is missing. Run npm run build before rendering real-model visuals.");
53	  }
54	
55	  const manifest = await loadManifest(options.manifestPath);
56	  const selectedCases = selectCases(manifest.cases, options.caseName);
57	  const resolvedCases = resolveCases(selectedCases, resolvedDataRoot);
58	  if (resolvedCases.length === 0) {
59	    console.log("Local real-model profile skipped: no renderable cases after asset checks.");
60	    return;
61	  }
62	
63	  const outputDir = options.outputDir ?? path.join(visualRoot, options.mode);
64	  await mkdir(outputDir, { recursive: true });
65	  await mkdir(path.join(visualRoot, "diff"), { recursive: true });
66	
67	  const server = await startStaticServer(resolvedDataRoot);
68	  let browser;
69	
70	  try {
71	    browser = await chromium.launch(browserLaunchOptions());
72	    const page = await browser.newPage({
73	      viewport: manifest.render.resolution,
74	      deviceScaleFactor: manifest.render.pixelRatio
75	    });
76	
77	    page.on("console", message => {
78	      if (message.type() === "warning") {
79	        console.warn(message.text());
80	      }
81	    });
82	
83	    await page.goto(`${server.origin}/__real_model_visual_renderer__`, {
84	      waitUntil: "networkidle"
85	    });
86	
87	    const renderedCases = await page.evaluate(async config => {
88	      return await globalThis.renderRealModelVisualRegressionCases(config);
89	    }, {
90	      render: manifest.render,
91	      cases: resolvedCases
92	    });
93	
94	    for (const renderedCase of renderedCases) {
95	      const buffer = Buffer.from(renderedCase.base64Png, "base64");
96	      const filePath = path.join(outputDir, `${renderedCase.name}.png`);
97	      await writeFile(filePath, buffer);
98	    }
99	
100	    const hashes = [];
101	    for (const renderedCase of renderedCases) {
102	      const filePath = path.join(outputDir, `${renderedCase.name}.png`);
103	      hashes.push({ name: renderedCase.name, sha256: await sha256File(filePath) });
104	    }
105	
106	    console.log(`Rendered ${hashes.length} real-model visual ${options.mode} case(s) to ${path.relative(repoRoot, outputDir)}`);
107	    for (const hash of hashes) {
108	      console.log(`${hash.sha256}  ${hash.name}.png`);
109	    }
110	  } finally {
111	    await browser?.close();
112	    await server.close();
113	  }
114	}
115	
116	function parseArgs(args) {
117	  const options = { mode: "current", caseName: undefined, outputDir: undefined, manifestPath, dataRoot: undefined };
118	
119	  for (let index = 0; index < args.length; index += 1) {
120	    const arg = args[index];
121	
122	    if (arg === "--mode") {
123	      const mode = args[index + 1];
124	      if (mode === undefined || !supportedModes.has(mode)) {
125	        throw new Error(`--mode must be one of: ${Array.from(supportedModes).join(", ")}`);
126	      }
127	      options.mode = mode;
128	      index += 1;
129	      continue;
130	    }
131	
132	    if (arg === "--case") {
133	      options.caseName = requireRawValue(args, (index += 1), arg);
134	      continue;
135	    }
136	
137	    if (arg === "--manifest") {
138	      options.manifestPath = path.resolve(requireRawValue(args, (index += 1), arg));
139	      continue;
140	    }
141	
142	    if (arg === "--data-root") {
143	      options.dataRoot = path.resolve(requireRawValue(args, (index += 1), arg));
144	      continue;
145	    }
146	
147	    if (arg === "--output-dir") {
148	      options.outputDir = path.resolve(requireRawValue(args, (index += 1), arg));
149	      continue;
150	    }
151	
152	    if (arg.startsWith("--")) {
153	      throw new Error(`Unknown option: ${arg}`);
154	    }
155	
156	    if (options.outputDir !== undefined) {
157	      throw new Error(`Unexpected extra argument: ${arg}`);
158	    }
159	    options.outputDir = path.resolve(arg);
160	  }
161	
162	  return options;
163	}
164	
165	function requireRawValue(args, index, flag) {
166	  const value = args[index];
167	  if (value === undefined || value.startsWith("--")) {
168	    throw new Error(`Missing value for ${flag}`);
169	  }
170	  return value;
171	}
172	
173	async function loadManifest(filePath) {
174	  const manifest = JSON.parse(await readFile(filePath, "utf8"));
175	  validateManifest(manifest);
176	  return manifest;
177	}
178	
179	function validateManifest(manifest) {
180	  if (!Array.isArray(manifest.cases)) {
181	    throw new Error("Real-model manifest must include a cases array");
182	  }
183	  if (!manifest.render?.resolution || manifest.render.pixelRatio === undefined) {
184	    throw new Error("Real-model manifest must include render.resolution and render.pixelRatio");
185	  }
186	
187	  const names = new Set();
188	  for (const visualCase of manifest.cases) {
189	    if (!/^[a-z0-9]+(?:-[a-z0-9]+)*$/.test(visualCase.name)) {
190	      throw new Error(`Real-model case name must be kebab-case: ${visualCase.name}`);
191	    }
192	    if (names.has(visualCase.name)) {
193	      throw new Error(`Duplicate real-model case name: ${visualCase.name}`);
194	    }
195	    names.add(visualCase.name);
196	    if (typeof visualCase.model !== "string" || visualCase.model.length === 0) {
197	      throw new Error(`Real-model case ${visualCase.name} must define model`);
198	    }
199	    if (visualCase.motion !== undefined && typeof visualCase.motion !== "string") {
200	      throw new Error(`Real-model case ${visualCase.name} motion must be a string when present`);
201	    }
202	    if (visualCase.timeSeconds !== undefined && (!Number.isFinite(visualCase.timeSeconds) || visualCase.timeSeconds < 0)) {
203	      throw new Error(`Real-model case ${visualCase.name} timeSeconds must be a non-negative number`);
204	    }
205	    if (!isValidCamera(visualCase.camera)) {
206	      throw new Error(`Real-model case ${visualCase.name} must define camera as "front-fit", "viewer-fit", or a camera config object`);
207	    }
208	  }
209	}
210	
211	function isValidCamera(camera) {
212	  if (camera === "front-fit" || camera === "viewer-fit") {
213	    return true;
214	  }
215	  return Boolean(
216	    camera &&
217	      typeof camera === "object" &&
218	      Array.isArray(camera.position) &&
219	      Array.isArray(camera.target) &&
220	      Number.isFinite(camera.fov)
221	  );
222	}
223	
224	function selectCases(cases, caseName) {
225	  if (caseName === undefined) {
226	    return cases;
227	  }
228	
229	  const selected = cases.filter(visualCase => visualCase.name === caseName);
230	  if (selected.length === 0) {
231	    throw new Error(`Unknown real-model visual case: ${caseName}`);
232	  }
233	  return selected;
234	}
235	
236	function resolveCases(cases, dataRoot) {
237	  const resolvedCases = [];
238	  for (const visualCase of cases) {
239	    const modelPath = resolveAssetPath(dataRoot, visualCase.model);
240	    if (modelPath === undefined || !existsSync(modelPath)) {
241	      console.warn(`Skipping real-model case ${visualCase.name}: model not found: ${visualCase.model}`);
242	      continue;
243	    }
244	
245	    let motionPath;
246	    if (visualCase.motion !== undefined) {
247	      motionPath = resolveAssetPath(dataRoot, visualCase.motion);
248	      if (motionPath === undefined || !existsSync(motionPath)) {
249	        console.warn(`Skipping real-model case ${visualCase.name}: motion not found: ${visualCase.motion}`);
250	        continue;
251	      }
252	    }
253	
254	    resolvedCases.push({
255	      ...visualCase,
256	      timeSeconds: visualCase.timeSeconds ?? 0,
257	      modelUrl: dataUrlFor(dataRoot, modelPath),
258	      motionUrl: motionPath === undefined ? undefined : dataUrlFor(dataRoot, motionPath)
259	    });
260	  }
261	  return resolvedCases;
262	}
263	
264	function resolveAssetPath(dataRoot, relativePath) {
265	  if (path.isAbsolute(relativePath)) {
266	    return undefined;
267	  }
268	  const resolved = path.resolve(dataRoot, relativePath);
269	  return isInsideRoot(resolved, dataRoot) ? resolved : undefined;
270	}
271	
272	function dataUrlFor(dataRoot, filePath) {
273	  return `/__mmd_data__/${path.relative(dataRoot, filePath).split(path.sep).map(encodeURIComponent).join("/")}`;
274	}
275	
276	async function startStaticServer(dataRoot) {
277	  const server = createServer(async (request, response) => {
278	    const requestUrl = new URL(request.url ?? "/", "http://127.0.0.1");
279	
280	    if (requestUrl.pathname === "/__real_model_visual_renderer__") {
281	      response.writeHead(200, { "content-type": "text/html; charset=utf-8" });
282	      response.end(rendererHtml());
283	      return;
284	    }
285	
286	    const filePath = resolveRequestPath(requestUrl.pathname, dataRoot);
287	    if (filePath === undefined) {
288	      response.writeHead(403);
289	      response.end("Forbidden");
290	      return;
291	    }
292	
293	    try {
294	      const body = await readFile(filePath);
295	      response.writeHead(200, {
296	        "content-type": mimeTypes.get(path.extname(filePath).toLowerCase()) ?? "application/octet-stream"
297	      });
298	      response.end(body);
299	    } catch {
300	      response.writeHead(404);
301	      response.end("Not found");
302	    }
303	  });
304	
305	  await new Promise((resolve, reject) => {
306	    server.once("error", reject);
307	    server.listen(0, "127.0.0.1", () => {
308	      server.off("error", reject);
309	      resolve();
310	    });
311	  });
312	
313	  const address = server.address();
314	  return {
315	    origin: `http://127.0.0.1:${address.port}`,
316	    close: () => new Promise(resolve => server.close(resolve))
317	  };
318	}
319	
320	function resolveRequestPath(requestPath, dataRoot) {
321	  const dataPrefix = "/__mmd_data__/";
322	  if (requestPath.startsWith(dataPrefix)) {
323	    const relativePath = decodePath(requestPath.slice(dataPrefix.length));
324	    const filePath = path.resolve(dataRoot, relativePath);
325	    return isInsideRoot(filePath, dataRoot) ? filePath : undefined;
326	  }
327	
328	  const normalizedPath = decodePath(requestPath).replace(/^[/\\]+/, "");
329	  const filePath = path.resolve(repoRoot, normalizedPath);
330	  return isInsideRoot(filePath, repoRoot) ? filePath : undefined;
331	}
332	
333	function decodePath(requestPath) {
334	  return path.normalize(decodeURIComponent(requestPath));
335	}
336	
337	function isInsideRoot(filePath, root) {
338	  const relative = path.relative(root, filePath);
339	  return relative === "" || (!relative.startsWith("..") && !path.isAbsolute(relative));
340	}
341	
342	function rendererHtml() {
343	  return `<!doctype html>
344	<html>
345	  <head>
346	    <meta charset="utf-8">
347	    <title>three-mmd-loader real-model visual renderer</title>
348	    <script type="importmap">
349	      {
350	        "imports": {
351	          "three": "/node_modules/three/build/three.module.js"
352	        }
353	      }
354	    </script>
355	  </head>
356	  <body>
357	    <script type="module">
358	      import * as THREE from "three";
359	      import {
360	        ThreeMmdLoader,
361	        applyMmdSelfShadowStateToThreeDirectionalLight,
362	        configureMmdSelfShadowDirectionalLight,
363	        fitMmdSelfShadowDirectionalLightToBox
364	      } from "/dist/three/index.js";
365	      import { sampleMmdSelfShadowTrack } from "/dist/runtime/index.js";
366	
367	      globalThis.renderRealModelVisualRegressionCases = async config => {
368	        const renderer = new THREE.WebGLRenderer({
369	          antialias: false,
370	          alpha: false,
371	          preserveDrawingBuffer: true,
372	          powerPreference: "high-performance"
373	        });
374	        renderer.setSize(config.render.resolution.width, config.render.resolution.height, false);
375	        renderer.setPixelRatio(config.render.pixelRatio);
376	        renderer.setClearColor(config.render.background, 1);
377	        renderer.outputColorSpace = THREE.SRGBColorSpace;
378	        renderer.toneMapping = THREE.NoToneMapping;
379	        if (config.render.shadow?.enabled === true) {
380	          renderer.shadowMap.enabled = true;
381	          renderer.shadowMap.type = THREE.PCFShadowMap;
382	        }
383	        document.body.append(renderer.domElement);
384	
385	        const results = [];
386	        for (const visualCase of config.cases) {
387	          const scene = buildScene(config.render);
388	          const loader = new ThreeMmdLoader({
389	            textureResolver: createCaseTextureResolver(visualCase.modelUrl),
390	            runtime: { physics: "none" }
391	          });
392	          const model = await loader.loadModel(await fetchBytes(visualCase.modelUrl));
393	          if (model.diagnostics.textures.length > 0) {
394	            for (const diagnostic of model.diagnostics.textures) {
395	              console.warn("Real-model texture diagnostic " + visualCase.name + ": " + diagnostic.code + " " + diagnostic.path);
396	            }
397	          }
398	          scene.add(model.root);
399	
400	          let selfShadowState;
401	          if (visualCase.motionUrl !== undefined) {
402	            const { animation } = await loader.loadAnimation(await fetchBytes(visualCase.motionUrl));
403	            model.setAnimation(animation);
404	            model.update(visualCase.timeSeconds, { physics: false });
405	            if (config.render.shadow?.enabled === true) {
406	              selfShadowState = sampleMmdSelfShadowTrack(animation.selfShadowFrames, visualCase.timeSeconds * 30);
407	            }
408	          } else {
409	            model.update(visualCase.timeSeconds, { physics: false });
410	          }
411	
412	          model.root.updateMatrixWorld(true);
413	          if (config.render.shadow?.enabled === true) {
414	            const shadowBounds = new THREE.Box3().setFromObject(model.root);
415	            fitMmdSelfShadowDirectionalLightToBox(scene.userData.mmdDirectionalLight, shadowBounds, {
416	              marginScale: config.render.shadow.directional?.marginScale ?? 0.06,
417	              minNear: config.render.shadow.directional?.minNear ?? 0.02,
418	              minFarSpan: config.render.shadow.directional?.minFarSpan ?? 2,
419	              maxFar: config.render.shadow.directional?.maxFar ?? 80
420	            });
421	            applyMmdSelfShadowStateToThreeDirectionalLight(scene.userData.mmdDirectionalLight, selfShadowState, {
422	              distanceScale: 100,
423	              minFar: 1,
424	              maxFar: 20,
425	              shadowIntensity: config.render.shadow.directional?.intensity ?? 0.55
426	            });
427	          }
428	          const camera = createCamera(visualCase.camera, model.root, config.render.resolution);
429	          renderer.render(scene, camera);
430	          await new Promise(requestAnimationFrame);
431	          results.push({
432	            name: visualCase.name,
433	            base64Png: renderer.domElement.toDataURL("image/png").split(",")[1]
434	          });
435	
436	          disposeScene(scene);
437	        }
438	
439	        renderer.dispose();
440	        renderer.domElement.remove();
441	        return results;
442	      };
443	
444	      function buildScene(render) {
445	        const scene = new THREE.Scene();
446	        scene.background = new THREE.Color(render.background);
447	
448	        const ambient = render.lights.ambient;
449	        scene.add(new THREE.AmbientLight(ambient.color, ambient.intensity));
450	
451	        const directional = render.lights.directional;
452	        const light = new THREE.DirectionalLight(directional.color, directional.intensity);
453	        light.position.fromArray(directional.position);
454	        if (render.shadow?.enabled === true) {
455	          light.castShadow = true;
456	          const shadow = render.shadow.directional ?? {};
457	          configureMmdSelfShadowDirectionalLight(light, {
458	            mapSize: shadow.mapSize ?? 1024,
459	            bias: shadow.bias ?? -0.0005,
460	            normalBias: shadow.normalBias ?? 0.01,
461	            shadowIntensity: shadow.intensity ?? 0.55,
462	            cameraLeft: shadow.left ?? -2,
463	            cameraRight: shadow.right ?? 2,
464	            cameraTop: shadow.top ?? 2,
465	            cameraBottom: shadow.bottom ?? -2,
466	            cameraNear: shadow.near ?? 0.1,
467	            cameraFar: shadow.far ?? 10
468	          });
469	          light.target.position.fromArray(directional.target ?? [0, 0, 0]);
470	          scene.add(light.target);
471	        }
472	        scene.add(light);
473	        scene.userData.mmdDirectionalLight = light;
474	
475	        return scene;
476	      }
477	
478	      async function fetchBytes(url) {
479	        const response = await fetch(url);
480	        if (!response.ok) {
481	          throw new Error("Failed to fetch local visual asset: " + url + " (" + response.status + ")");
482	        }
483	        return new Uint8Array(await response.arrayBuffer());
484	      }
485	
486	      function createCaseTextureResolver(modelUrl) {
487	        return {
488	          async resolve(texturePath) {
489	            return new URL(normalizeTexturePath(texturePath), new URL(".", new URL(modelUrl, location.href))).toString();
490	          }
491	        };
492	      }
493	
494	      function normalizeTexturePath(texturePath) {
495	        return texturePath.replaceAll("\\\\", "/").replace(/^\\.\\/+/u, "");
496	      }
497	
498	      function createCamera(cameraConfig, mesh, resolution) {
499	        const box = new THREE.Box3().setFromObject(mesh);
500	        const sphere = box.getBoundingSphere(new THREE.Sphere());
501	        const radius = Math.max(sphere.radius, 1);
502	
503	        if (cameraConfig === "front-fit") {
504	          const aspect = resolution.width / resolution.height;
505	          const halfHeight = radius * 1.18;
506	          const halfWidth = halfHeight * aspect;
507	          const camera = new THREE.OrthographicCamera(-halfWidth, halfWidth, halfHeight, -halfHeight, 0.1, radius * 10 + 100);
508	          camera.position.set(sphere.center.x, sphere.center.y, sphere.center.z + radius * 3);
509	          camera.lookAt(sphere.center);
510	          camera.updateProjectionMatrix();
511	          return camera;
512	        }
513	
514	        if (cameraConfig === "viewer-fit") {
515	          const camera = new THREE.PerspectiveCamera(22, resolution.width / resolution.height, Math.max(radius / 100, 0.01), Math.max(radius * 40, 100));
516	          camera.position.copy(sphere.center).add(new THREE.Vector3(0, radius * 0.15, radius * 5.2));
517	          camera.lookAt(sphere.center);
518	          camera.updateProjectionMatrix();
519	          return camera;
520	        }
521	
522	        const camera = new THREE.PerspectiveCamera(cameraConfig.fov, resolution.width / resolution.height, cameraConfig.near ?? 0.1, cameraConfig.far ?? radius * 10 + 100);
523	        camera.position.fromArray(cameraConfig.position);
524	        camera.lookAt(...cameraConfig.target);
525	        camera.updateProjectionMatrix();
526	        return camera;
527	      }
528	
529	      function disposeScene(scene) {
530	        scene.traverse(object => {
531	          if (object.geometry) {
532	            object.geometry.dispose();
533	          }
534	          const material = object.material;
535	          if (Array.isArray(material)) {
536	            material.forEach(disposeMaterial);
537	          } else if (material) {
538	            disposeMaterial(material);
539	          }
540	        });
541	      }
542	
543	      function disposeMaterial(material) {
544	        for (const value of Object.values(material)) {
545	          if (value && typeof value === "object" && "isTexture" in value) {
546	            value.dispose();
547	          }
548	        }
549	        material.dispose();
550	      }
551	    </script>
552	  </body>
553	</html>`;
554	}
555	
556	await main();
