1	#!/usr/bin/env node
2	import { spawn } from "node:child_process";
3	import { existsSync } from "node:fs";
4	import { mkdir, readFile, writeFile } from "node:fs/promises";
5	import path from "node:path";
6	import { fileURLToPath } from "node:url";
7	import { PNG } from "pngjs";
8	
9	const __dirname = path.dirname(fileURLToPath(import.meta.url));
10	const repoRoot = path.resolve(__dirname, "..", "..");
11	const outputRoot = path.join(repoRoot, "test-results", "visual", "local-self-shadow");
12	const viewerLighting = {
13	  background: "#ffffff",
14	  ambient: { color: "#ffffff", intensity: 0.15 },
15	  directional: {
16	    color: "#ffffff",
17	    intensity: 1.0,
18	    position: [3, 4, 5],
19	    target: [0, 0.9, 0]
20	  }
21	};
22	
23	async function main() {
24	  const options = await resolveOptions(parseArgs(process.argv.slice(2)));
25	  const currentDir = path.join(options.outputDir, "current");
26	  await mkdir(currentDir, { recursive: true });
27	
28	  const onManifestPath = path.join(options.outputDir, "manifest-on.json");
29	  const offManifestPath = path.join(options.outputDir, "manifest-off.json");
30	  await writeFile(onManifestPath, `${JSON.stringify(createManifest(options, true), null, 2)}\n`);
31	  await writeFile(offManifestPath, `${JSON.stringify(createManifest(options, false), null, 2)}\n`);
32	
33	  await runNodeScript("scripts/visual-regression/render-real-models.mjs", [
34	    "--manifest", onManifestPath,
35	    "--data-root", options.dataRoot,
36	    "--output-dir", currentDir
37	  ]);
38	  await runNodeScript("scripts/visual-regression/render-real-models.mjs", [
39	    "--manifest", offManifestPath,
40	    "--data-root", options.dataRoot,
41	    "--output-dir", currentDir
42	  ]);
43	
