52	async function compareShadowPair(comparison, outputDir) {
53	  const shadowOnPath = path.join(outputDir, `${comparison.shadowOn}.png`);
54	  const shadowOffPath = path.join(outputDir, `${comparison.shadowOff}.png`);
55	  const [shadowOn, shadowOff] = await Promise.all([readPng(shadowOnPath), readPng(shadowOffPath)]);
56	  if (shadowOn.width !== shadowOff.width || shadowOn.height !== shadowOff.height) {
57	    throw new Error(`Image size mismatch for ${comparison.name}`);
58	  }
59	
60	  const roi = normalizeRoi(comparison.receiverRoi, shadowOn.width, shadowOn.height);
61	  const darkeningValues = [];
62	  const shadowOnLuminanceValues = [];
63	  let darkeningSum = 0;
64	  let shadowOnLuminanceSum = 0;
65	  let shadowPixelCount = 0;
66	  let roiPixelCount = 0;
67	  let outsideDeltaSum = 0;
68	  let outsidePixelCount = 0;
69	
70	  for (let y = 0; y < shadowOn.height; y += 1) {
71	    for (let x = 0; x < shadowOn.width; x += 1) {
72	      const offset = (y * shadowOn.width + x) * 4;
73	      const onLum = luminance(shadowOn.data, offset);
74	      const offLum = luminance(shadowOff.data, offset);
75	      if (x >= roi.x && x < roi.x + roi.width && y >= roi.y && y < roi.y + roi.height) {
76	        const darkening = Math.max(0, offLum - onLum);
77	        darkeningValues.push(darkening);
78	        shadowOnLuminanceValues.push(onLum);
79	        darkeningSum += darkening;
80	        shadowOnLuminanceSum += onLum;
81	        roiPixelCount += 1;
82	        if (darkening >= 0.035) {
83	          shadowPixelCount += 1;
84	        }
85	      } else {
