87	        outsidePixelCount += 1;
88	      }
89	    }
90	  }
91	
92	  darkeningValues.sort((a, b) => a - b);
93	  shadowOnLuminanceValues.sort((a, b) => a - b);
94	  const receiverMeanDarkening = darkeningSum / Math.max(1, roiPixelCount);
95	  const receiverP95Darkening =
96	    darkeningValues[Math.min(darkeningValues.length - 1, Math.ceil(darkeningValues.length * 0.95) - 1)] ?? 0;
97	  const shadowPixelRatio = shadowPixelCount / Math.max(1, roiPixelCount);
98	  const shadowOnMeanLuminance = shadowOnLuminanceSum / Math.max(1, roiPixelCount);
