107	    shadowOnMeanLuminance >= thresholds.shadowOnMeanLuminanceMin &&
108	    shadowOnP05Luminance >= thresholds.shadowOnP05LuminanceMin &&
109	    outsideRoiMeanDelta <= thresholds.outsideRoiMeanDeltaMax;
