111	  return {
112	    name: comparison.name,
113	    shadowOn: comparison.shadowOn,
114	    shadowOff: comparison.shadowOff,
115	    receiverRoi: roi,
116	    receiverMeanDarkening: round(receiverMeanDarkening),
117	    receiverP95Darkening: round(receiverP95Darkening),
118	    shadowPixelRatio: round(shadowPixelRatio),
119	    shadowOnMeanLuminance: round(shadowOnMeanLuminance),
120	    shadowOnP05Luminance: round(shadowOnP05Luminance),
121	    outsideRoiMeanDelta: round(outsideRoiMeanDelta),
