109	async function compareCase({ visualCase, baselineDir, currentDir, thresholdDegrees }) {
110	  const baselinePath = path.join(baselineDir, `${visualCase.name}.json`);
111	  const currentPath = path.join(currentDir, `${visualCase.name}.json`);
112	  if (!existsSync(baselinePath)) {
113	    throw new Error(`Missing baseline snapshot: ${path.relative(repoRoot, baselinePath)}`);
114	  }
115	  if (!existsSync(currentPath)) {
116	    throw new Error(`Missing current snapshot: ${path.relative(repoRoot, currentPath)}`);
117	  }
118	
119	  const baseline = JSON.parse(await readFile(baselinePath, "utf8"));
120	  const current = JSON.parse(await readFile(currentPath, "utf8"));
121	  const watchBones = normalizeWatchBones(visualCase.watchBones);
122	  const boneResults = [];
123	
124	  for (const boneName of watchBones) {
125	    const baselineBone = baseline.bones?.[boneName];
126	    const currentBone = current.bones?.[boneName];
127	    const result = compareBone(boneName, baselineBone, currentBone, thresholdDegrees);
128	    boneResults.push(result);
129	  }
130	
131	  const maxAngleDegrees = Math.max(0, ...boneResults.map((result) => result.angleDegrees ?? 0));
132	  return {
133	    case: visualCase.name,
134	    thresholdDegrees,
135	    maxAngleDegrees: roundMetric(maxAngleDegrees),
136	    pass: boneResults.every((result) => result.pass),
137	    bones: boneResults
138	  };
139	}
140	
141	function compareBone(boneName, baselineBone, currentBone, thresholdDegrees) {
142	  if (!baselineBone?.found && !currentBone?.found) {
143	    return { bone: boneName, found: false, pass: true };
144	  }
145	  if (!baselineBone?.found || !currentBone?.found) {
146	    return {
147	      bone: boneName,
148	      found: false,
149	      pass: false,
150	      reason: "bone found state changed"
151	    };
152	  }
153	  const localAngleDegrees = quaternionAngleDegrees(
154	    readQuaternion(baselineBone.localQuaternion),
155	    readQuaternion(currentBone.localQuaternion)
156	  );
157	  const hasBaselineWorld = baselineBone.worldQuaternion !== undefined;
158	  const hasCurrentWorld = currentBone.worldQuaternion !== undefined;
159	  if (hasBaselineWorld !== hasCurrentWorld) {
160	    return {
161	      bone: boneName,
162	      found: true,
163	      pass: false,
164	      reason: "world quaternion presence changed"
165	    };
166	  }
167	  const worldAngleDegrees = hasBaselineWorld
168	    ? quaternionAngleDegrees(
169	        readQuaternion(baselineBone.worldQuaternion),
170	        readQuaternion(currentBone.worldQuaternion)
171	      )
172	    : undefined;
173	  const maxAngleDegrees = Math.max(localAngleDegrees, worldAngleDegrees ?? 0);
174	  return {
175	    bone: boneName,
176	    found: true,
177	    localAngleDegrees: roundMetric(localAngleDegrees),
178	    worldAngleDegrees:
179	      worldAngleDegrees === undefined ? undefined : roundMetric(worldAngleDegrees),
180	    angleDegrees: roundMetric(maxAngleDegrees),
181	    pass: maxAngleDegrees <= thresholdDegrees
182	  };
183	}
184	
185	function normalizeWatchBones(watchBones) {
186	  if (watchBones === undefined) {
187	    return defaultWatchBones;
188	  }
189	  return watchBones.filter((boneName) => typeof boneName === "string" && boneName.length > 0);
190	}
191	
192	function readQuaternion(value) {
193	  if (
194	    value === undefined ||
195	    !Number.isFinite(value.x) ||
196	    !Number.isFinite(value.y) ||
197	    !Number.isFinite(value.z) ||
198	    !Number.isFinite(value.w)
