209	
210	function numericThreshold(value, fallback) {
211	  if (value === undefined) {
212	    return fallback;
213	  }
214	  if (typeof value !== "number" || !Number.isFinite(value) || value < 0) {
215	    throw new Error(`Invalid rest pose quaternion threshold: ${value}`);
216	  }
217	  return value;
218	}
219	
220	function roundMetric(value) {
221	  return Number(value.toFixed(6));
222	}
223	
224	function formatMetric(value) {
225	  return value.toFixed(6);
226	}
227	
228	function requireRawValue(args, index, flag) {
229	  const value = args[index];
230	  if (value === undefined || value.startsWith("--")) {
231	    throw new Error(`Missing value for ${flag}`);
232	  }
233	  return value;
234	}
