97	export async function compareCase({ id, baselinePath, currentPath, diffPath, thresholds, metric = "js", flipPath }) {
98	  if (!existsSync(baselinePath)) {
99	    throw new Error(`Missing baseline PNG for ${id}: ${path.relative(repoRoot, baselinePath)}`);
100	  }
101	  if (!existsSync(currentPath)) {
102	    throw new Error(`Missing current PNG for ${id}: ${path.relative(repoRoot, currentPath)}`);
103	  }
104	
105	  const [baseline, current] = await Promise.all([readPng(baselinePath), readPng(currentPath)]);
106	  if (baseline.width !== current.width || baseline.height !== current.height) {
107	    throw new Error(
108	      `Image size mismatch for ${id}: baseline=${baseline.width}x${baseline.height}, current=${current.width}x${current.height}`
109	    );
110	  }
111	
112	  if (metric === "flip") {
113	    return await compareCaseWithFlip({
114	      id,
115	      baselinePath,
116	      currentPath,
117	      diffPath,
118	      thresholds,
119	      flipPath
120	    });
121	  }
122	
123	  const pixelCount = baseline.width * baseline.height;
124	  const distances = new Float64Array(pixelCount);
125	  const diff = new PNG({ width: baseline.width, height: baseline.height });
126	  let sum = 0;
127	  let max = 0;
128	
129	  for (let pixel = 0; pixel < pixelCount; pixel += 1) {
130	    const offset = pixel * 4;
131	    const distance = perceptualDistance(baseline.data, current.data, offset);
132	    distances[pixel] = distance;
133	    sum += distance;
134	    max = Math.max(max, distance);
135	    writeHeatmapPixel(diff.data, offset, distance);
136	  }
137	
138	  distances.sort();
139	  const mean = sum / pixelCount;
140	  const p95 = distances[Math.min(distances.length - 1, Math.ceil(distances.length * 0.95) - 1)];
141	  const pass = mean <= thresholds.mean && p95 <= thresholds.p95;
142	
143	  await writePng(diff, diffPath);
144	
145	  return {
146	    case: id,
147	    metric,
148	    mean: roundMetric(mean),
149	    p95: roundMetric(p95),
150	    max: roundMetric(max),
151	    thresholds,
152	    pass
153	  };
154	}
