190	export function perceptualDistance(baselineData, currentData, offset) {
191	  const baseAlpha = baselineData[offset + 3] / 255;
192	  const currentAlpha = currentData[offset + 3] / 255;
193	  const alphaDelta = Math.abs(baseAlpha - currentAlpha);
194	  const dr = srgbToLinear(baselineData[offset] / 255) - srgbToLinear(currentData[offset] / 255);
195	  const dg = srgbToLinear(baselineData[offset + 1] / 255) - srgbToLinear(currentData[offset + 1] / 255);
196	  const db = srgbToLinear(baselineData[offset + 2] / 255) - srgbToLinear(currentData[offset + 2] / 255);
197	  const colorDistance = Math.sqrt(0.2126 * dr * dr + 0.7152 * dg * dg + 0.0722 * db * db);
198	
199	  return Math.min(1, Math.sqrt(colorDistance * colorDistance + alphaDelta * alphaDelta));
200	}
