202	function writeHeatmapPixel(data, offset, distance) {
203	  const clamped = Math.max(0, Math.min(1, distance));
204	  const intensity = Math.round(clamped * 255);
205	  const red = clamped < 0.5 ? Math.round(clamped * 2 * 255) : 255;
206	  const green = clamped < 0.5 ? 255 : Math.round((1 - (clamped - 0.5) * 2) * 255);
207	
208	  data[offset] = red;
209	  data[offset + 1] = green;
210	  data[offset + 2] = 0;
211	  data[offset + 3] = intensity;
212	}
