354	    child.stdout.setEncoding("utf8");
355	    child.stderr.setEncoding("utf8");
356	    child.stdout.on("data", chunk => {
357	      stdout += chunk;
358	    });
359	    child.stderr.on("data", chunk => {
360	      stderr += chunk;
361	    });
362	    child.on("error", error => {
363	      reject(new Error(`Failed to run NVIDIA FLIP executable "${executable}": ${error.message}`));
364	    });
365	    child.on("close", code => {
366	      if (code === 0) {
367	        resolve({ stdout, stderr });
