27	// Linear bezier interpolation control points (standard MMD defaults).
28	// Layout: 4 axes (X,Y,Z,R) × 16 bytes each, interleaved in a specific pattern.
29	// Using the common linear values: x1=x2=20, y1=y2=107 for each axis.
30	const LINEAR_INTERPOLATION = new Uint8Array([
31	  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,
32	  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,
33	  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,
34	  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,  20, 20, 107, 107,
35	]);
