37	/**
38	 * Generates a VMD with one keyframe per entry in `boneFrames`.
39	 *
40	 * @param {object} options
41	 * @param {string} [options.modelName]  Model name written into VMD header (cosmetic).
42	 * @param {Array<{boneName: string, frame?: number, quaternion: [number,number,number,number]}>} options.boneFrames
43	 *   Each entry sets one bone keyframe. quaternion = [x, y, z, w].
44	 * @param {Array<{frame?: number, mode: number, distance: number}>} [options.selfShadowFrames]
45	 * @returns {Uint8Array}
46	 */
47	export function generateMinimalVmd({ modelName = "", boneFrames = [], selfShadowFrames = [] }) {
48	  const out = [];
49	
50	  const u32 = (v) => {
51	    const b = new ArrayBuffer(4);
52	    new DataView(b).setUint32(0, v, true);
53	    out.push(...new Uint8Array(b));
54	  };
55	  const i32 = (v) => {
56	    const b = new ArrayBuffer(4);
57	    new DataView(b).setInt32(0, v, true);
58	    out.push(...new Uint8Array(b));
59	  };
60	  const f32 = (v) => {
61	    const b = new ArrayBuffer(4);
62	    new DataView(b).setFloat32(0, v, true);
63	    out.push(...new Uint8Array(b));
64	  };
65	  const fixedText = (s, length) => {
66	    // ASCII/Shift-JIS: ASCII subset works directly as byte values
67	    for (let i = 0; i < length; i++) {
68	      out.push(i < s.length ? s.charCodeAt(i) : 0);
69	    }
70	  };
71	
72	  // Signature (30 bytes)
73	  fixedText("Vocaloid Motion Data 0002", 30);
74	  // Model name (20 bytes)
75	  fixedText(modelName.substring(0, 20), 20);
76	
77	  // Bone frame count
78	  i32(boneFrames.length);
79	
80	  for (const bf of boneFrames) {
81	    fixedText(bf.boneName, 15);                    // bone name (15 bytes)
82	    u32(bf.frame ?? 0);                            // frame number
83	    f32(0); f32(0); f32(0);                        // translation (zero)
84	    const [qx, qy, qz, qw] = bf.quaternion;
85	    f32(qx); f32(qy); f32(qz); f32(qw);           // rotation quaternion
86	    out.push(...LINEAR_INTERPOLATION);             // interpolation (64 bytes)
87	  }
88	
89	  // Remaining sections: morph, camera, light
90	  i32(0); i32(0); i32(0);
91	  i32(selfShadowFrames.length);
92	  for (const frame of selfShadowFrames) {
93	    u32(frame.frame ?? 0);
94	    out.push(frame.mode & 0xff);
95	    f32(frame.distance);
96	  }
97	  // property
98	  i32(0);
99	
100	  return new Uint8Array(out);

