69	  }
70	  const modelName = readFixedText(reader, 20, shiftJisDecoder);
71	  const boneTrackCounts = new Map<string, number>();
72	  const morphTrackCounts = new Map<string, number>();
73	  let maxFrame = 0;
74	  const boneCount = readCount(reader, "bone");
75	  for (let index = 0; index < boneCount; index += 1) {
76	    const name = readFixedText(reader, 15, shiftJisDecoder);
