131	  const morphCount = readCount(reader, "morph");
132	  for (let index = 0; index < morphCount; index += 1) {
133	    const name = readFixedText(reader, 15, shiftJisDecoder);
134	    const track = morphTracks[name];
135	    const writeIndex = morphWriteIndices.get(name) ?? 0;
136	    morphWriteIndices.set(name, writeIndex + 1);
137	    const frame = reader.u32();
