28	export function applyMmdCameraStateToThreeCamera(
29	  camera: THREE.PerspectiveCamera,
30	  state: CameraState,
31	  options?: ApplyMmdCameraStateOptions
32	): THREE.PerspectiveCamera | THREE.OrthographicCamera {
33	  const activeCamera =
34	    state.perspective || !options?.orthographicCamera ? camera : options.orthographicCamera;
35	  const target = options?.target ?? defaultTargetScratch;
36	  const offset = options?.offset ?? defaultOffsetScratch;
37	  const euler = options?.euler ?? defaultEulerScratch;
38	  const quaternion = options?.quaternion ?? defaultQuaternionScratch;
39	  const up = options?.up ?? defaultUpScratch;
40	  const outsideParent = options?.outsideParent;
41	  target.set(state.position[0], state.position[1], -state.position[2]);
42	  if (outsideParent) {
43	    target.add(outsideParent.getWorldPosition(options?.outsideParentScratch ?? defaultOutsideParentScratch));
44	  } else if (options?.outsideParentWorldPosition) {
45	    target.add(options.outsideParentWorldPosition);
46	  }
47	  euler.set(-state.rotation[0], -state.rotation[1], state.rotation[2], "YXZ");
48	  quaternion.setFromEuler(euler).invert();
49	  offset.set(0, 0, -state.distance).applyQuaternion(quaternion);
50	  if (state.distance > 0) {
51	    quaternion.multiply(positiveDistanceCameraFlip);
52	  }
53	  activeCamera.position.copy(target).add(offset);
54	  activeCamera.quaternion.copy(quaternion);
55	  activeCamera.up.copy(up.set(0, 1, 0).applyQuaternion(quaternion));
56	  activeCamera.userData.mmdCameraPerspective = state.perspective;
57	  if (activeCamera instanceof THREE.PerspectiveCamera) {
58	    activeCamera.fov = Math.max(state.fov, options?.minFov ?? 1);
59	  } else if (activeCamera instanceof THREE.OrthographicCamera) {
60	    const fov = Math.max(state.fov, options?.minFov ?? 1);
61	    const height = Math.max(
62	      2 * Math.abs(state.distance) * Math.tan(THREE.MathUtils.degToRad(fov) / 2),
63	      options?.minOrthographicHeight ?? 1e-3
64	    );
65	    const halfHeight = height / 2;
66	    const halfWidth = halfHeight * (options?.aspect ?? 1);
67	    activeCamera.left = -halfWidth;
68	    activeCamera.right = halfWidth;
69	    activeCamera.top = halfHeight;
70	    activeCamera.bottom = -halfHeight;
71	    activeCamera.near = camera.near;
72	    activeCamera.far = camera.far;
73	  }
74	  activeCamera.updateProjectionMatrix();
75	  return activeCamera;
